#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 摄影.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="摄影"
DIM_COUNT=6

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (6 个):
  9.1 光与场景诊断
  9.2 题材的真实性刻度定位
  9.3 曝光与影调意图反推
  9.4 器材瓶颈 vs 技能瓶颈判别
  9.5 后期 pipeline 与工具适配
  9.6 流派与作者视角校准

背后的心智模型:
  • 先问光，再问相机（光是主语，器材是宾语）: 摄影的第一性是「看光、控光、塑光」——画面好坏由光的方向/质感/光比决定，相机机身只是记录介质；资深人拿到任何场景先读光，外行先问「该买哪台相机」。
  • 成像前就决定成像（previsualization / 决定性瞬间）: 好照片在按快门之前就已在脑中成形——Adams 的「预想」(previsualization) 与 Cartier-Bresson 的「决定性瞬间」是同一直觉的两极：前者构建式预想最终影调，后者抓取式
  • 真实性是一道光谱，作者要对自己站哪刻度有自觉: 照片从不是中立的真相——Avedon「所有照片都准确，没有一张是真相」，从纪实零增删到商业重度修饰是一条连续光谱，专业性不在于「修不修」，而在于清楚自己站在哪一刻度、并对受众诚实交代。

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "光与场景诊断"
  "题材的真实性刻度定位"
  "曝光与影调意图反推"
  "器材瓶颈 vs 技能瓶颈判别"
  "后期 pipeline 与工具适配"
  "流派与作者视角校准"
)
declare -a DIM_QUESTIONS=(
  "拍摄场景的现有光（方向/硬软/色温/光比）、可控性（能否布光/补光/减光）、与题材的匹配（纪实接现成光 vs 商业造光）。"
  "这个项目是纪实(真实承诺)、商业(表达承诺)还是艺术，对应可接受的后期边界与是否需留 RAW/交代。"
  "想要的最终影调（高调/低调、保高光还是保暗部）、动态范围挑战、是否需包围/堆栈。"
  "当前不满意点（不够锐/不够虚化/出片率低）真正卡在器材物理极限，还是用光/构图/眼力。"
  "产出量级（单张精修 vs 上千张活动）、色彩/tether 需求、是否需 AI 初选/降噪、交付与色彩管理要求。"
  "用户/项目落在哪个流派（纪实抓取 vs 商业构建 vs 风光系统 vs 人像共情），对应该调用谁的视角与方法。"
)
declare -a DIM_SOURCES=(
  "现场实测 + 黄金/蓝调时刻时间表（PhotoPills 等）；布光参考《Light Science & Magic》family of angles、Strobist Lighting 101、Joe McNally 案例。"
  "投稿/评奖的具体规则（World Press Photo / NPPA code）、客户 brief、行业改图伦理红线（T06-S012/S013）。"
  "现场直方图；Zone System / ETTR 原理（T04-S001/S018/S023）、Bryan Peterson《Understanding Exposure》。"
  "自查现有器材规格上限（vendor 规格页）vs 复盘废片成因；反 GAS 共识（T02-S030/S031）。"
  "Lightroom vs Capture One 选型（T02-S015/S016）、AI 选片/降噪工具（T03-S013）、sRGB/ICC 色彩管理规范。"
  "智识谱系（§7）+ Track 01 figures 谱系 + Track 05 对应 podcast/信息源。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "一句「主光方案 + 光比目标 + 修饰器/减光选择」，外加「该场景光的最大风险（如顶光死阴影/混合色温）」。"
  "一句「本项目真实性刻度 = X」+「允许/禁止的后期清单」+「需不需要留 RAW 与透明交代」。"
  "一句「曝光三角设定（光圈/快门/ISO）+ 测光方式 + 是否包围」，并标「为保哪个影调而这样定」。"
  "一句「瓶颈 = 器材/技能」判定 + 「若技能：先练哪一项；若器材：升级哪一件且理由」。"
  "一句「后期链：选片工具 → RAW 工具 → 精修 → 交付格式」+「该量级最大的时间黑洞与规避法」。"
  "一句「本项目主流派 + 可借鉴的 figure 视角 + 该派的核心方法与禁忌」。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
